fun describe(x: Int): String {
    return when (x) {
        0    -> "zero"
        else -> "other"
    }
}

fun describe(x: Int): String {
    return when (x) {
        0    -> "zero"
        1    -> "one"
        else -> "other"
    }
}

fun describe(x: Int): String {
    return when (x) {
        0    -> "zero"
        1    -> "one"
        2    -> "two"
        else -> "many"
    }
}

fun describe(x: Int): String {
    return when {
        x < 0  -> "negative"
        x == 0 -> "zero"
        else   -> "positive"
    }
}

fun describe(x: Int): String {
    return when {
        x == 0 -> "zero"
        else   -> "other"
    }
}

enum class Shape {
    Circle, Square, Triangle, Rectangle, Pentagon, Hexagon, Octagon, Ellipse, Rhombus, Star;

    val isRound: Boolean
        get() = when (this) {
            Circle, Ellipse -> true
            Square, Triangle, Rectangle, Pentagon, Hexagon, Octagon, Rhombus, Star -> false
        }
}

enum class Season { Spring, Summer, Autumn, Winter }
fun isWarm(s: Season): Boolean = when (s) {
    Season.Spring, Season.Summer, Season.Autumn -> true
    else -> false
}
